var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"그쪽으로 갔어! 쫓아!!","JPN":"そっちに行ったわ！　追いましょう！！","ENG":"They went that way! Go after them!","TWN":"她往那邊去了！快追！！"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"도망쳐어-.","JPN":"逃げろぉー","ENG":"Ruuun.","TWN":"逃囉——"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"제길. 앞이 안 보이잖아?","JPN":"くっ、視界が見えない！？","ENG":"Damn it, I can't see anything.","TWN":"可惡，前面看不見了！"},"stage":{"bg":"WHITE","slots":{"L":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"날랜 몸놀림을 바탕으로 시기적절한 상황에 폭발과 연막인가.","JPN":"あの素早い身のこなしからくる、的確なタイミングでの爆発と煙幕攻撃……。","ENG":"A well-timed explosion and smokescreen based on her dexterous movements.","TWN":"憑藉敏捷的身手，在適當的時機投放爆破和煙霧彈。"},"stage":{"bg":"WHITE","slots":{"L":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"훌륭하다. 아무래도 괜한 허세는 아니었나 보군.","JPN":"見事だ。ただの自信過剰な奴ではなかったようだな。","ENG":"Impressive. It seems like she wasn't bluffing.","TWN":"真厲害，看來不是虛張聲勢。"},"stage":{"bg":"WHITE","slots":{"L":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_PRIDE"}}}},{"id":"L15_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"감탄하고 있을 때가 아니야, 준. 이러다 다른 두 명은 놓친다고!!","JPN":"感心している場合じゃないでしょ、ジュン。このままじゃ、他の二人をあのまま取り逃しちゃう！！","ENG":"This isn't the time to be impressed, Jun. The other two are getting away!","TWN":"現在不是讚嘆的時候，朱恩。這樣下去會放跑另外兩個人的！！"},"stage":{"bg":"WHITE","slots":{"L":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_PRIDE"}}}},{"id":"L16_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"걱정마라, 동생이여. 이런 연막으로는 파사의 시안을 가릴 수 없다.","JPN":"心配無用だ、妹よ。こんな煙幕ごときでは私の視界を遮ることはできない。","ENG":"Do not fret, little sister. This measly smokescreen cannot blind the evil-hunting eye.","TWN":"別擔心，我的妹妹。這點煙霧是遮不住破邪之眼的。"},"stage":{"bg":"WHITE","slots":{"L":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"이 정도로 날뛰었으니 곧 한계일 터.","JPN":"これだけ暴れたんだ、本人だって限界が来ているだろう。","ENG":"She should be close to her limits after exhausting her energy.","TWN":"鬧劇差不多該落幕了。"},"stage":{"bg":"WHITE","slots":{"L":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"크레데레 대위기-.","JPN":"クレデレ、絶体絶命です。","ENG":"Credere, in danger.","TWN":"克蕾妲莉大危機——"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"세상이 도는구나아-.","JPN":"世界が回るぅ。","ENG":"The world is spinning...","TWN":"世界在旋轉——"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"CRF 남발로 인한 한시적인 혼란증세인가. 아무래도 여기까지인 모양이군.","JPN":"CRFを乱発したことによる、一時的な意識混濁か。さすがにこの辺が限界だったようだな。","ENG":"She seems to be confused due to overusing her CRF. This should be it.","TWN":"是因為濫用CRF引起的暫時性混亂症狀嗎？看來到此為止了。"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_PRIDE"}}}},{"id":"L26_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"나, 나도 알고 있었다고? 혹시 몰라서 준을 시험해본 거야!","JPN":"そ、それぐらい私だってわかるわよ！　ちょっとジュンを試しただけなんだから！","ENG":"I-I knew that too! I was just testing you, Jun!","TWN":"我、我也知道！？我剛是在測試一下你！"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_PRIDE"}}}},{"id":"L29_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"승부가 난 모양이군요. 뱃고동 소리가 들려오는 걸 보니 제 동생도 도착한 모양입니다.","JPN":"勝負はあったようですね。船笛の音も聞こえていますし、僕の弟もまもなく到着するでしょう。","ENG":"Seems like it's settled. Plus, I can hear the sound of a foghorn, which means my brother has arrived.","TWN":"看來勝負已分。另外，這個汽笛聲，說明我弟弟也到了。"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"사랑하는 내 동생, 터커! 형이 목 빠지도록 기다렸단다!","JPN":"愛する私の弟、ターカーよ！　ずっと待っていたぞ！","ENG":"My dear brother, Tucker! I was waiting for you!","TWN":"我親愛的弟弟，塔克！哥哥我等你等得好苦！"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"대체 뭘 하다가 이제야 온 거…","JPN":"いったいどこで道草を食って……","ENG":"What took you so long–","TWN":"你到底在做什麼，現在才到…"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":" 응?","JPN":" うん？","ENG":" Huh?","TWN":"嗯？"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"유감~ 터커가 아니라 샤크스 해적단이지롱.","JPN":"残念だったな～。私たちはシャークス海賊団。ターカーじゃないぞ。","ENG":"Sorry! It's the Sharks, not Tucker.","TWN":"抱歉～我不是塔克，而是大白鯊喔。"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"다, 당신들은 누굽니까?","JPN":"だ、誰です！？","ENG":"W-who are you?","TWN":"你、你們是誰？"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"저 깃발은 터커 해적단의 상징. 틀림없는 제 동생의 배란 말입니다!","JPN":"あの旗はターカー海賊団のシンボル。僕の弟の船で間違いありません！","ENG":"That flag represents the Tucker Pirates. That's my brother's ship!","TWN":"那面旗幟是塔克海盜團的象徵。那絕對是我弟弟的船！"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"별거 아니야. 목적지가 같아서 동행하려 했는데 작당모의를 하는 걸 봐서 말이지.","JPN":"大したことじゃない。目的地が同じだったから同行しようとしたら、コソコソと作戦会議するのを見かけてね。","ENG":"It's not a big deal. We just accompanied them heading to the same place. And then we figured out they were scheming something.","TWN":"沒什麼大不了的。本來只是目的地相同想要同行，但他們好像別有意圖。"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"담가지기 전에 먼저 담갔죠! 그야말로 해적!","JPN":"だからこっちが海に沈められる前に、先に沈めてやったというわけですわ！　まさに海賊という感じでしょう！","ENG":"We dunked them before they dunked us! The ultimate pirate move!","TWN":"先下手為強！這就是海盜的作風！"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L43_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"안 담갔어. 그냥 부두 적당한 곳에 묶어 놨을 뿐이잖아.","JPN":"沈めたのは嘘。桟橋に縛っておいたよ。","ENG":"We didn't dunk anyone. We just tied them up somewhere on the docks.","TWN":"沒事，只是在碼頭把他們綁起來而已。"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_PRIDE"}}}}]`);export{e as default};